using FloatingAICopilot.Models;
using Microsoft.AspNetCore.Mvc;

namespace FloatingAICopilot.Controllers;

[ApiController]
[Route("api/[controller]")]
public class {Feature}Controller : ControllerBase
{
    private readonly ILogger<{Feature}Controller> _logger;

    public {Feature}Controller(ILogger<{Feature}Controller> logger)
    {
        _logger = logger;
    }

    [HttpGet]
    public IActionResult GetAll() => Ok(new List<{Model}>());

    [HttpGet("{id}")]
    public IActionResult Get(int id) => Ok(new {Model}());

    [HttpPost]
    public IActionResult Create({Model} model) => Created(nameof(Get), model);

    [HttpPut("{id}")]
    public IActionResult Update(int id, {Model} model) => Ok(model);

    [HttpDelete("{id}")]
    public IActionResult Delete(int id) => NoContent();
}
